mapper.insert:
INSERT INTO SURVEY (
SURVEY_NO, SURVEY_NM, SURVEY_CN, SURVEY_TY_CD, SURVEY_QITEM_CN, SURVEY_BGNG_DT, SURVEY_END_DT, SURVEY_STTS_CD, RGTR_ID, APT_CD
) VALUES (
'SV' || TO_CHAR(SYSTIMESTAMP, 'MMDDHH24MISSFF3'),
#{surveyNm}, #{surveyCn}, #{surveyTypeCd}, #{surveyQitemCn},
TO_DATE(#{surveyBgngDt}, 'YYYY-MM-DD'), TO_DATE(#{surveyEndDt}, 'YYYY-MM-DD'),
#{surveySttsCd}, #{rgtrId}, #{aptCd}
)

mapper.select:
SELECT RSPNS_CN

FROM SURVEY_RSPNS

WHERE SURVEY_NO = #{surveyNo}
  AND USER_NO = #{userNo}
  AND ROWNUM = 1

mapper.insert:
INSERT INTO SURVEY_RSPNS (
RSPNS_NO, SURVEY_NO, RSPNS_CN, REG_DT, USER_NO, HO_NO
) VALUES (
'RS' || LPAD(SEQ_SURVEY_RSPNS.NEXTVAL, 13, '0'),
#{surveyNo}, #{response}, SYSDATE, #{userNo}, #{hoNo}
)

mapper.select:
SELECT COUNT(*)

FROM SURVEY_RSPNS

WHERE SURVEY_NO = #{surveyNo}
  AND USER_NO = #{userNo}

SELECT RSPNS_CN

FROM SURVEY_RSPNS

WHERE SURVEY_NO = #{surveyNo}

SELECT COUNT(*)

FROM SURVEY_RSLT

WHERE SURVEY_NO = #{surveyNo}
  AND QITEM_NM = #{qitemNm}
  AND ANSR_CN = #{ansrCn}

mapper.update:
UPDATE SURVEY_RSLT

SET ANSR_CNT = ANSR_CNT + 1

WHERE SURVEY_NO = #{surveyNo}
  AND QITEM_NM = #{qitemNm}
  AND ANSR_CN = #{ansrCn}

mapper.insert:
INSERT INTO SURVEY_RSLT (
